import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"更新日誌: 版本歷史 | Plannotator","description":"瞭解 Plannotator 版本歷史和新功能。檢視主要更新、Bug 修復和效能改進，掌握程式碼審查、圖像標註、Obsidian 整合等新特性。","frontmatter":{"title":"更新日誌: 版本歷史 | Plannotator","sidebarTitle":"看看新功能","subtitle":"更新日誌: 版本歷史 | Plannotator","description":"瞭解 Plannotator 版本歷史和新功能。檢視主要更新、Bug 修復和效能改進，掌握程式碼審查、圖像標註、Obsidian 整合等新特性。","tags":["更新日誌","版本歷史","新功能","Bug 修復"],"order":1},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/changelog/release-notes/index.md","filePath":"zh-tw/backnotprop/plannotator/changelog/release-notes/index.md"}'),n={name:"zh-tw/backnotprop/plannotator/changelog/release-notes/index.md"};function l(i,t,s,p,g,c){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="更新日誌-plannotator-版本歷史和新功能" tabindex="-1">更新日誌：Plannotator 版本歷史和新功能 <a class="header-anchor" href="#更新日誌-plannotator-版本歷史和新功能" aria-label="Permalink to &quot;更新日誌：Plannotator 版本歷史和新功能&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>✅ 瞭解 Plannotator 的版本歷史和新功能</li><li>✅ 掌握每個版本的主要更新和改進</li><li>✅ 瞭解 Bug 修復和效能最佳化</li></ul><hr><h2 id="最新版本" tabindex="-1">最新版本 <a class="header-anchor" href="#最新版本" aria-label="Permalink to &quot;最新版本&quot;">​</a></h2><h3 id="v0-6-7-2026-01-24" tabindex="-1">v0.6.7 (2026-01-24) <a class="header-anchor" href="#v0-6-7-2026-01-24" aria-label="Permalink to &quot;v0.6.7 (2026-01-24)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>Comment mode</strong>：新增 Comment 模式，支援在計畫中直接輸入評論</li><li><strong>Type-to-comment shortcut</strong>：新增快速鍵支援，直接輸入評論內容</li></ul><p><strong>改進</strong>：</p><ul><li>修復 OpenCode 外掛的 sub-agent blocking 問題</li><li>修復 prompt injection 安全漏洞（CVE）</li><li>改進 OpenCode 中的 agent switching 智慧偵測</li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Comment mode: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationToolbar.tsx#L23-L42" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationToolbar.tsx</code></a></li><li>Type-to-comment: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationToolbar.tsx#L80-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationToolbar.tsx</code></a></li></ul><hr><h3 id="v0-6-6-2026-01-20" tabindex="-1">v0.6.6 (2026-01-20) <a class="header-anchor" href="#v0-6-6-2026-01-20" aria-label="Permalink to &quot;v0.6.6 (2026-01-20)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>修復 OpenCode plugin 的 CVE 安全漏洞</li><li>修復 sub-agent blocking 問題，防止 prompt injection</li><li>改進 agent switching 的智慧偵測邏輯</li></ul><p><strong>原始碼參考</strong>：</p><ul><li>OpenCode plugin: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L245-L280" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li><li>Agent switching: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/agentSwitch.ts#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/utils/agentSwitch.ts</code></a></li></ul><hr><h3 id="v0-6-5-2026-01-15" tabindex="-1">v0.6.5 (2026-01-15) <a class="header-anchor" href="#v0-6-5-2026-01-15" aria-label="Permalink to &quot;v0.6.5 (2026-01-15)&quot;">​</a></h3><p><strong>改進</strong>：</p><ul><li><strong>Hook timeout 增加</strong>：將 hook timeout 從預設值增加到 4 天，適應長時間執行的 AI 計畫</li><li><strong>修復 copy 功能</strong>：保留 copy 操作中的 newlines</li><li><strong>新增 Cmd+C 快速鍵</strong>：新增 Cmd+C 快速鍵支援</li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Hook timeout: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L44-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></li><li>Copy newlines: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L150-L170" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></li></ul><hr><h3 id="v0-6-4-2026-01-10" tabindex="-1">v0.6.4 (2026-01-10) <a class="header-anchor" href="#v0-6-4-2026-01-10" aria-label="Permalink to &quot;v0.6.4 (2026-01-10)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>Cmd+Enter 快速鍵</strong>：支援使用 Cmd+Enter（Windows: Ctrl+Enter）提交核准或回饋</li></ul><p><strong>改進</strong>：</p><ul><li>最佳化鍵盤操作體驗</li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Keyboard shortcuts: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L323" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a> (Cmd+Enter 快速鍵功能在各元件中直接實作)</li></ul><hr><h3 id="v0-6-3-2026-01-05" tabindex="-1">v0.6.3 (2026-01-05) <a class="header-anchor" href="#v0-6-3-2026-01-05" aria-label="Permalink to &quot;v0.6.3 (2026-01-05)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>修復 skip-title-generation-prompt 問題</li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Skip title: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L67-L71" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li></ul><hr><h3 id="v0-6-2-2026-01-01" tabindex="-1">v0.6.2 (2026-01-01) <a class="header-anchor" href="#v0-6-2-2026-01-01" aria-label="Permalink to &quot;v0.6.2 (2026-01-01)&quot;">​</a></h3><p><strong>修復</strong>：</p><ul><li>修復 OpenCode 外掛中 HTML 檔案未包含在 npm 套件中的問題</li></ul><p><strong>原始碼參考</strong>：</p><ul><li>OpenCode plugin build: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li></ul><hr><h3 id="v0-6-1-2025-12-20" tabindex="-1">v0.6.1 (2025-12-20) <a class="header-anchor" href="#v0-6-1-2025-12-20" aria-label="Permalink to &quot;v0.6.1 (2025-12-20)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>Bear 整合</strong>：支援將核准的計畫自動儲存到 Bear 筆記 App</li></ul><p><strong>改進</strong>：</p><ul><li>改進 Obsidian 整合的標籤產生邏輯</li><li>最佳化 Obsidian vault 偵測機制</li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Bear 整合: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L280" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Obsidian 整合: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L136-L220" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li></ul><hr><h2 id="重大功能發佈" tabindex="-1">重大功能發佈 <a class="header-anchor" href="#重大功能發佈" aria-label="Permalink to &quot;重大功能發佈&quot;">​</a></h2><h3 id="code-review-功能-2026-01" tabindex="-1">Code Review 功能 (2026-01) <a class="header-anchor" href="#code-review-功能-2026-01" aria-label="Permalink to &quot;Code Review 功能 (2026-01)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>程式碼審查工具</strong>：執行 <code>/plannotator-review</code> 指令，視覺化審查 Git diff</li><li><strong>行級註解</strong>：點擊行號選擇程式碼範圍，新增 comment/suggestion/concern 類型的註解</li><li><strong>多種 diff 檢視</strong>：支援切換 uncommitted/staged/last-commit/branch 等不同的 diff 類型</li><li><strong>Agent 整合</strong>：傳送結構化回饋給 AI agent，支援自動回應</li></ul><p><strong>使用方法</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在專案目錄中執行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>相關教學</strong>：</p><ul><li><a href="./../../platforms/code-review-basics/">程式碼審查基礎</a></li><li><a href="./../../platforms/code-review-annotations/">新增程式碼註解</a></li><li><a href="./../../platforms/code-review-diff-types/">切換 Diff 檢視</a></li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Code review server: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></li><li>Code review UI: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></li><li>Git diff 工具: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></li></ul><hr><h3 id="圖像標註功能-2026-01" tabindex="-1">圖像標註功能 (2026-01) <a class="header-anchor" href="#圖像標註功能-2026-01" aria-label="Permalink to &quot;圖像標註功能 (2026-01)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>上傳圖片</strong>：在計畫和程式碼審查中上傳圖片附件</li><li><strong>標註工具</strong>：提供畫筆、箭頭、圓形三種標註工具</li><li><strong>視覺化標註</strong>：在圖片上直接標註，增強審查回饋效果</li></ul><p><strong>相關教學</strong>：</p><ul><li><a href="./../../platforms/plan-review-images/">新增圖像標註</a></li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Image annotator: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/ImageAnnotator/index.tsx" target="_blank" rel="noreferrer"><code>packages/ui/components/ImageAnnotator/index.tsx</code></a></li><li>Upload API: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L160-L180" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></li></ul><hr><h3 id="obsidian-整合-2025-12" tabindex="-1">Obsidian 整合 (2025-12) <a class="header-anchor" href="#obsidian-整合-2025-12" aria-label="Permalink to &quot;Obsidian 整合 (2025-12)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>自動偵測 vaults</strong>：自動偵測 Obsidian vault 設定檔路徑</li><li><strong>自動儲存計畫</strong>：核准的計畫自動儲存到 Obsidian</li><li><strong>產生 frontmatter</strong>：自動包含 created、source、tags 等 frontmatter</li><li><strong>智慧標籤擷取</strong>：從計畫內容中擷取關鍵字作為標籤</li></ul><p><strong>設定方式</strong>： 無需額外設定，Plannotator 會自動偵測 Obsidian 安裝路徑。</p><p><strong>相關教學</strong>：</p><ul><li><a href="./../../advanced/obsidian-integration/">Obsidian 整合</a></li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Obsidian 偵測: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L136-L145" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Obsidian 儲存: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L220" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Frontmatter 產生: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L50-L80" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></li></ul><hr><h3 id="url-分享功能-2025-11" tabindex="-1">URL 分享功能 (2025-11) <a class="header-anchor" href="#url-分享功能-2025-11" aria-label="Permalink to &quot;URL 分享功能 (2025-11)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>無後端分享</strong>：將計畫和註解壓縮到 URL hash 中，無需後端伺服器</li><li><strong>一鍵分享</strong>：點擊 Export → Share as URL，產生分享連結</li><li><strong>唯讀模式</strong>：協作者開啟 URL 後可檢視但無法提交決策</li></ul><p><strong>技術實作</strong>：</p><ul><li>使用 Deflate 壓縮演算法</li><li>Base64 編碼 + URL 安全字元替換</li><li>支援最大 payload 約 7 個標籤</li></ul><p><strong>相關教學</strong>：</p><ul><li><a href="./../../advanced/url-sharing/">URL 分享</a></li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Sharing utils: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/sharing.ts" target="_blank" rel="noreferrer"><code>packages/ui/utils/sharing.ts</code></a></li><li>Share hook: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/hooks/useSharing.ts" target="_blank" rel="noreferrer"><code>packages/ui/hooks/useSharing.ts</code></a></li></ul><hr><h3 id="遠端-devcontainer-模式-2025-10" tabindex="-1">遠端/Devcontainer 模式 (2025-10) <a class="header-anchor" href="#遠端-devcontainer-模式-2025-10" aria-label="Permalink to &quot;遠端/Devcontainer 模式 (2025-10)&quot;">​</a></h3><p><strong>新增功能</strong>：</p><ul><li><strong>遠端模式支援</strong>：在 SSH、devcontainer、WSL 等遠端環境中使用 Plannotator</li><li><strong>固定連接埠</strong>：透過環境變數設定固定連接埠</li><li><strong>連接埠轉發</strong>：自動輸出 URL 供使用者手動開啟瀏覽器</li><li><strong>瀏覽器控制</strong>：透過 <code>PLANNOTATOR_BROWSER</code> 環境變數控制是否開啟瀏覽器</li></ul><p><strong>環境變數</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE=1</code>：啟用遠端模式</li><li><code>PLANNOTATOR_PORT=3000</code>：設定固定連接埠</li><li><code>PLANNOTATOR_BROWSER=disabled</code>：停用自動開啟瀏覽器</li></ul><p><strong>相關教學</strong>：</p><ul><li><a href="./../../advanced/remote-mode/">遠端/Devcontainer 模式</a></li><li><a href="./../../advanced/environment-variables/">環境變數設定</a></li></ul><p><strong>原始碼參考</strong>：</p><ul><li>Remote mode: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/remote.ts" target="_blank" rel="noreferrer"><code>packages/server/remote.ts</code></a></li><li>Browser control: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/browser.ts" target="_blank" rel="noreferrer"><code>packages/server/browser.ts</code></a></li></ul><hr><h2 id="版本相容��" tabindex="-1">版本相容�� <a class="header-anchor" href="#版本相容��" aria-label="Permalink to &quot;版本相容��&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plannotator 版本</th><th>Claude Code</th><th>OpenCode</th><th>Bun 最低版本</th></tr></thead><tbody><tr><td>v0.6.x</td><td>2.1.7+</td><td>1.0+</td><td>1.0+</td></tr><tr><td>v0.5.x</td><td>2.1.0+</td><td>0.9+</td><td>0.7+</td></tr></tbody></table><p><strong>升級建議</strong>：</p><ul><li>保持 Plannotator 為最新版本，以取得最新功能和安全修復</li><li>Claude Code 和 OpenCode 也應保持最新版本</li></ul><hr><h2 id="授權條款變更" tabindex="-1">授權條款變更 <a class="header-anchor" href="#授權條款變更" aria-label="Permalink to &quot;授權條款變更&quot;">​</a></h2><p><strong>目前版本（v0.6.7+）</strong>：Business Source License 1.1 (BSL-1.1)</p><p><strong>授權條款詳情</strong>：</p><ul><li>允許：個人使用、內部商業使用</li><li>限制：提供託管服務、SaaS 產品</li><li>詳情見 <a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a></li></ul><hr><h2 id="回饋與支援" tabindex="-1">回饋與支援 <a class="header-anchor" href="#回饋與支援" aria-label="Permalink to &quot;回饋與支援&quot;">​</a></h2><p><strong>回報問題</strong>：</p><ul><li>GitHub Issues: <a href="https://github.com/backnotprop/plannotator/issues" target="_blank" rel="noreferrer">https://github.com/backnotprop/plannotator/issues</a></li></ul><p><strong>功能建議</strong>：</p><ul><li>在 GitHub Issues 中提交 feature request</li></ul><p><strong>安全漏洞</strong>：</p><ul><li>請透過私密管道回報安全漏洞</li></ul><hr><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>你已經瞭解了 Plannotator 的版本歷史和新功能。</p><p>接下來可以：</p><ul><li>返回 <a href="./../../start/getting-started/">快速開始</a> 學習如何安裝和使用</li><li>檢視 <a href="./../../faq/common-problems/">常見問題</a> 解決使用中的問題</li><li>閱讀 <a href="./../../appendix/api-reference/">API 參考</a> 瞭解所有 API 端點</li></ul></blockquote>`,121)])])}const u=a(n,[["render",l]]);export{h as __pageData,u as default};
